import scala.collection.mutable

def s(s: String): String = {
    val vowels = Set('a', 'e', 'i', 'o', 'u')

    // 1. Count frequencies and record first appearance index for each vowel
    val frequencies = mutable.Map[Char, Int]()
    val firstAppearance = mutable.Map[Char, Int]()

    for (i <- 0 until s.length) {
        val char = s(i)
        if (vowels.contains(char)) {
            frequencies.updateWith(char) {
                case Some(count) => Some(count + 1)
                case None => Some(1)
            }
            if (!firstAppearance.contains(char)) {
                firstAppearance.put(char, i)
            }
        }
    }

    // 2. Get a list of unique vowels present in s
    val uniqueVowels = frequencies.keys.toList

    // 3. Sort the unique vowels based on the criteria
    // Sorting criteria:
    // a) Primary: Frequency (descending)
    // b) Secondary: First appearance index (ascending)
    val sortedVowels = uniqueVowels.sortBy { vowel =>
        // Return a tuple for comparison: (-frequency, first_index)
        // Minimizing this tuple achieves the desired sorting:
        // - Larger frequency results in a smaller negative number (comes first).
        // - For equal frequency, smaller first index comes first.
        (-frequencies(vowel), firstAppearance(vowel))
    }

    // 4. Create the replacement mapping
    // This mapping stores the sorted sequence of vowels, but we need to place them back in order.
    // Since the problem requires placing the sorted sequence of *all* vowels back into the original vowel slots,
    // we need to reconstruct the sequence of vowels from the sorted list, maintaining multiplicity.

    // Count the required occurrences of each sorted vowel
    val vowelCounts = frequencies.toMap

    // Create the final ordered list of vowels to be inserted (e.g., if sortedVowels = ['a', 'o'], 
    // and counts are a=4, o=3, this list should be ['a', 'a', 'a', 'a', 'o', 'o', 'o'])
    val replacementSequence = mutable.ListBuffer[Char]()
    for (vowel <- sortedVowels) {
        val count = vowelCounts(vowel)
        for (i <- 1..count) {
            replacementSequence.add(vowel)
        }
    }

    val finalVowelSequence = replacementSequence.toList

    // 5. Construct the result string
    val resultChars = Array[Char](s.length)
    var vowelIndex = 0

    for (i <- 0 until s.length) {
        val char = s(i)
        if (vowels.contains(char)) {
            // Replace the vowel with the next vowel from the sorted sequence
            resultChars(i) = finalVowelSequence(vowelIndex)
            vowelIndex += 1
        } else {
            // Keep consonants as they are
            resultChars(i) = char
        }
    }

    new String(resultChars)
