import scala.collection.immutable.List
import scala.util.matching.Regex

object Solution {
  private val vowels = Set('a', 'e', 'i', 'o', 'u')

  /**
   * Reorders the vowels in the string s based on frequency (non-increasing) 
   * and then by first appearance order for ties.
   * 
   * @param s The input string.
   * @return The modified string.
   */
  def s(s: String): String = {
    // 1. Identify all vowel positions and extract vowels
    val charArray = s.toCharArray
    val vowelIndices = new scala.collection.mutable.ListBuffer[Int]()
    val vowelsList = new scala.collection.mutable.ListBuffer[Char]()

    for (i <- 0 until s.length) {
      val char = charArray(i)
      if (vowels.contains(char)) {
        vowelIndices += i
        vowelsList += char
      }
    }

    // 2. Calculate frequency and first appearance index for each unique vowel
    val frequencyMap = vowelsList.groupBy(identity).mapValues(_.size)

    // Store information about each unique vowel: (char, frequency, first_index)
    val vowelInfoMap = new scala.collection.mutable.HashMap[Char, (Int, Int)]()

    // Track the first appearance index for each vowel type
    val firstAppearance = new scala.collection.mutable.HashMap[Char, Int]()

    for (i <- 0 until s.length) {
      val char = charArray(i)
      if (vowels.contains(char) && !firstAppearance.contains(char)) {
        firstAppearance(char) = i
      }
    }

    // Populate vowelInfoMap
    for (v <- vowels) {
      if (frequencyMap.contains(v)) {
        val freq = frequencyMap(v)
        val firstIdx = firstAppearance(v)
        vowelInfoMap(v) = (freq, firstIdx)
      }
    }

    // 3. Sort the unique vowels based on the criteria
    // Sorting criteria:
    // 1. Frequency (descending)
    // 2. First appearance index (ascending) - for ties in frequency
    val sortedVowels = vowelInfoMap.keys.toList.sorted(
      (v1, v2) => {
        val (freq1, idx1) = vowelInfoMap(v1)
        val (freq2, idx2) = vowelInfoMap(v2)

        // Compare frequency (descending)
        if (freq1 != freq2) {
          freq2.compareTo(freq1) // Descending order for frequency
        } else {
          // Frequencies are equal, compare first index (ascending)
          idx1.compareTo(idx2) // Ascending order for first index
        }
      }
    )

    // 4. Construct the sorted sequence of vowels
    val sortedVowelsSequence = new scala.collection.mutable.ListBuffer[Char]()
    for (v <- sortedVowels) {
      val count = frequencyMap(v)
      for (i <- 1 to count) {
        sortedVowelsSequence += v
      }
    }
    val replacementVowels = sortedVowelsSequence.toList

    // 5. Create the resulting character array
    val resultChars = charArray.clone()

    // Place the sorted vowels back into their original positions
    for (i <- 0 until vowelIndices.length) {
      val originalIndex = vowelIndices(i)
      resultChars(originalIndex) = replacementVowels(i)
    }

    // 6. Return the resulting string
    new String(resultChars)
  }
}
