object Solution {
  def s(s: String): String = {
    val vowels = Set('a', 'e', 'i', 'o', 'u')
    val n = s.length

    // 1. Collect all vowel occurrences and their original indices
    val vowelIndices = for (i <- 0 until n) yield if (vowels.contains(s(i))) (i, s(i)) else None
    val vowelData = vowelIndices.flatten.toList

    // 2. Calculate frequency and first appearance index for each unique vowel
    val freqMap = s.groupBy(v => v).mapValues(_.size).toMap
    val firstAppearance = s.zipWithIndex.filter { case (c, _) => vowels.contains(c) }.map { case (c, i) => c -> i }.toMap

    // 3. Create a list of tuples for sorting: (vowel, frequency, first_index)
    val uniqueVowels = vowelData.map(_._2).toSet.toList
    val sortableVowels = uniqueVowels.map { v =>
      (v, freqMap(v), firstAppearance(v))
    }.toList

    // 4. Sort the vowels based on the criteria:
    //    a) Frequency (non-increasing/descending)
    //    b) First appearance index (ascending/non-decreasing)
    val sortedVowels = sortableVowels.sortBy { case (_, freq, firstIdx) =>
      (-freq.toDouble, firstIdx.toDouble) // Sorting by negative frequency achieves descending order for frequency
    }.map(_._1) // Extract just the vowel character in the sorted order

    // 5. Reconstruct the string
    val resultChars = Array.ofDim[Char](n)
    var sortedVowelIdx = 0

    for (i <- 0 until n) {
      if (vowels.contains(s(i))) {
        // This position was a vowel, place the next sorted vowel here
        resultChars(i) = sortedVowels(sortedVowelIdx)
        sortedVowelIdx += 1
      } else {
        // This position was a consonant, keep it as is
        resultChars(i) = s(i)
      }
    }

    new String(resultChars)
  }
}
